let select_all_to_production=document.querySelector("#select-all-to-production");let add_all_to_production=document.querySelector("#add-all-to-production");select_all_to_production?.addEventListener("click",function(){select_all_to_production.classList.toggle("selected");if(select_all_to_production.classList.contains("selected")){select_all_to_production.innerText="Снять выбор";select_all_to_production.classList.remove("btn-outline-primary");select_all_to_production.classList.add("btn-primary")}else{select_all_to_production.innerText="Выбрать все";select_all_to_production.classList.add("btn-outline-primary");select_all_to_production.classList.remove("btn-primary")}const products=document.querySelectorAll(".add-all-to-production");products.forEach(checkbox=>{if(!checkbox.disabled){checkbox.checked=select_all_to_production.classList.contains("selected")}});const checkboxes=document.querySelectorAll(".add-all-to-production");const atLeastOneChecked=Array.from(checkboxes).some(cb=>cb.checked);if(atLeastOneChecked){add_all_to_production.classList.remove("d-none")}else{add_all_to_production.classList.add("d-none")}});let checkboxs_all_to_production=document.querySelectorAll(".add-all-to-production");for(checkbox_all_to_production of checkboxs_all_to_production){checkbox_all_to_production?.addEventListener("click",function(){const checkboxes=document.querySelectorAll(".add-all-to-production");const atLeastOneChecked=Array.from(checkboxes).some(cb=>cb.checked);if(atLeastOneChecked){add_all_to_production.classList.remove("d-none")}else{add_all_to_production.classList.add("d-none")}})}